// src/AnaSayfa.js
import React, { useEffect, useMemo, useState } from "react";

/** ENV
 * REACT_APP_API_BASE_URL=https://...
 * REACT_APP_ODAK_API_KEY=...
 */
const API_BASE = process.env.REACT_APP_API_BASE_URL || "";
const ODAK_KEY = process.env.REACT_APP_ODAK_API_KEY || "";

/** Basit UI yardımcıları (paketsiz) */
const Card = ({ className = "", children }) => (
    <div className={`rounded-lg border border-white/10 bg-white/5 ${className}`}>{children}</div>
);
const CardHeader = ({ children, className = "" }) => <div className={`px-5 pt-4 ${className}`}>{children}</div>;
const CardTitle = ({ children, className = "" }) => <h3 className={`text-base font-semibold ${className}`}>{children}</h3>;
const CardDescription = ({ children, className = "" }) => (
    <p className={`text-sm text-gray-400 mt-1 ${className}`}>{children}</p>
);
const CardContent = ({ children, className = "" }) => <div className={`p-5 ${className}`}>{children}</div>;
const Badge = ({ children, className = "" }) => (
    <span className={`inline-flex items-center gap-1 rounded-full border px-2 py-0.5 text-xs ${className}`}>{children}</span>
);
const Button = ({ children, className = "", variant = "solid", ...props }) => (
    <button
        className={`inline-flex items-center justify-center gap-2 rounded-lg px-3 py-2 text-sm transition ${variant === "outline"
                ? "border border-white/10 bg-white/5 text-gray-200 hover:bg-white/10"
                : variant === "ghost"
                    ? "text-gray-300 hover:text-white hover:bg-white/5"
                    : "bg-gradient-to-r from-indigo-500 to-cyan-500 text-white shadow-lg"
            } ${className}`}
        {...props}
    >
        {children}
    </button>
);

/** Domain sabitleri */
const ALLOWED_PROJECTS = new Set([
    "BUNGE LÜLEBURGAZ FTL", "BUNGE GEBZE FTL", "BUNGE PALET", "REKA FTL", "EKSUN GIDA FTL", "SARUHAN FTL",
    "PEPSİ FTL", "MUTLU MAKARNA SPOT FTL", "TEKİRDAĞ UN FTL", "AYDINLI MODA FTL", "ADKOTURK FTL",
    "ADKOTURK FTL ENERJİ İÇECEĞİ", "SGS FTL", "BSH FTL", "ALTERNA GIDA FTL", "DERYA OFİS FTL",
    "SAPRO FTL", "MARMARA CAM FTL", "FAKİR FTL", "MODERN KARTON FTL", "KÜÇÜKBAY FTL",
]);

const normalizeProjectName = (name) => {
    const map = {
        "BUNGE DİLOVASI-REYSAŞ": "BUNGE GEBZE FTL",
        "BUNGE PALET": "BUNGE PALET",
        "BUNGE LÜLEBURGAZ FTL": "BUNGE LÜLEBURGAZ FTL",
    };
    return map[name] || name;
};
const addDays = (dateStr, delta) => {
    const d = new Date(dateStr + "T00:00:00");
    d.setDate(d.getDate() + delta);
    return d.toISOString().slice(0, 10);
};

/** ODAK API */
async function fetchOdakDataForRange(startStr, endStr) {
    if (!API_BASE || !ODAK_KEY) {
        throw new Error("ODAK API env eksik (REACT_APP_API_BASE_URL / REACT_APP_ODAK_API_KEY).");
    }
    const wideStart = addDays(startStr, -2);
    const wideEnd = addDays(endStr, 2);

    const payload = { startDate: `${wideStart}T00:00:00`, endDate: `${wideEnd}T23:59:59`, userId: 1 };

    const res = await fetch(`${API_BASE}/odak`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: ODAK_KEY },
        body: JSON.stringify(payload),
    });

    if (!res.ok) {
        const txt = await res.text().catch(() => "");
        throw new Error(`ODAK API ${res.status} — ${txt || res.statusText}`);
    }

    const result = await res.json();
    const items = Array.isArray(result.Data) ? result.Data : [];

    const filtered = items.filter((item) => {
        const pickupDate = item.PickupDate?.split("T")[0];
        const req = item.TMSVehicleRequestDocumentNo;
        return (
            pickupDate && pickupDate >= startStr && pickupDate <= endStr &&
            item.OrderStatu !== 200 && req && !req.startsWith("BOS") && item.ProjectName
        );
    });

    const projectMap = new Map();
    for (const item of filtered) {
        const project = normalizeProjectName(item.ProjectName?.trim() || "");
        const reqNo = item.TMSVehicleRequestDocumentNo;
        const hasDespatch = item.TMSDespatchDocumentNo && !item.TMSDespatchDocumentNo.startsWith("BOS");
        const vehicleWorking = (item?.VehicleWorkingName || "").toUpperCase();

        if (!projectMap.has(project)) {
            projectMap.set(project, {
                ProjectName: project,
                talepSet: new Set(),
                tedarikSet: new Set(),
                spotSet: new Set(),
                filoSet: new Set(),
            });
        }
        const proj = projectMap.get(project);
        proj.talepSet.add(reqNo);
        if (hasDespatch) proj.tedarikSet.add(reqNo);
        if (vehicleWorking.includes("SPOT")) proj.spotSet.add(reqNo);
        else if (vehicleWorking.includes("FİLO") || vehicleWorking.includes("FILO")) proj.filoSet.add(reqNo);
    }

    const finalData = Array.from(projectMap.values())
        .map((p) => ({
            ProjectName: p.ProjectName,
            Talep: p.talepSet.size,
            Tedarik: p.tedarikSet.size,
            Verilemeyen: p.talepSet.size - p.tedarikSet.size,
            Spot: p.spotSet.size,
            Filo: p.filoSet.size,
        }))
        .filter((p) => ALLOWED_PROJECTS.has(p.ProjectName));

    return { list: finalData, raw: filtered };
}

/** Sayfa */
const AnaSayfa = () => {
    const todayStr = new Date().toISOString().slice(0, 10);
    const [startDate, setStartDate] = useState(todayStr);
    const [endDate, setEndDate] = useState(todayStr);

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const [odakRows, setOdakRows] = useState([]); // proje bazlı reel sayılar
    const [lastUpdated, setLastUpdated] = useState(null);

    const handleLoad = async () => {
        setLoading(true);
        setError(null);
        try {
            const { list } = await fetchOdakDataForRange(startDate, endDate);
            setOdakRows(list);
            setLastUpdated(new Date());
        } catch (e) {
            setError(e.message || "ODAK verisi alınamadı");
            setOdakRows([]);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        handleLoad();
        const iv = setInterval(() => handleLoad(), 30000);
        return () => clearInterval(iv);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [startDate, endDate]);

    const kpi = useMemo(() => {
        const sum = (key) => odakRows.reduce((s, r) => s + (Number(r[key]) || 0), 0);
        return {
            talep: sum("Talep"),
            tedarik: sum("Tedarik"),
            verilemeyen: sum("Verilemeyen"),
            spot: sum("Spot"),
            filo: sum("Filo"),
        };
    }, [odakRows]);

    return (
        <div className="min-h-screen bg-gradient-to-b from-gray-950 via-gray-900 to-black text-gray-100">
            {/* Üst Bar */}
            <header className="sticky top-0 z-30 border-b border-white/5 backdrop-blur supports-[backdrop-filter]:bg-gray-950/50">
                <div className="w-full flex items-center justify-between px-6 py-4">
                    <div className="flex items-center gap-3">
                        <div className="grid size-9 place-items-center rounded-xl bg-gradient-to-tr from-indigo-500 to-cyan-400 shadow-lg shadow-indigo-500/20">
                            <span className="text-white">🚚</span>
                        </div>
                        <div>
                            <p className="text-xs uppercase tracking-widest text-gray-400">Lojistik Kontrol Merkezi</p>
                            <h1 className="text-lg font-semibold">CargoFlow</h1>
                        </div>
                    </div>
                    <div className="flex flex-wrap gap-3 items-center">
                        <div className="relative">
                            <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">📅</span>
                            <input
                                type="date"
                                value={startDate}
                                max={endDate}
                                onChange={(e) => setStartDate(e.target.value)}
                                className="w-40 rounded-lg border border-white/10 bg-white/5 pl-9 pr-3 py-2 text-sm text-gray-200"
                            />
                        </div>
                        <div className="relative">
                            <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">📅</span>
                            <input
                                type="date"
                                value={endDate}
                                min={startDate}
                                onChange={(e) => setEndDate(e.target.value)}
                                className="w-40 rounded-lg border border-white/10 bg-white/5 pl-9 pr-3 py-2 text-sm text-gray-200"
                            />
                        </div>
                        <Button variant="outline" onClick={handleLoad}>Yenile</Button>
                    </div>
                </div>
            </header>

            {/* İçerik */}
            <main className="w-full space-y-6 px-6 py-6">
                {loading && <div className="text-sm text-gray-400">ODAK verisi yükleniyor…</div>}

                {!loading && error && (
                    <Card>
                        <CardHeader>
                            <CardTitle>Hata</CardTitle>
                            <CardDescription>ODAK verisi alınamadı</CardDescription>
                        </CardHeader>
                        <CardContent className="text-sm text-rose-300">{error}</CardContent>
                    </Card>
                )}

                {!loading && !error && (
                    <>
                        {/* KPI’lar — tam genişlik, otomatik saran grid */}
                        <section className="grid gap-4 grid-cols-[repeat(auto-fit,minmax(220px,1fr))]">
                            {[
                                { label: "Reel Talep", val: kpi.talep, icon: "📝" },
                                { label: "Reel Tedarik", val: kpi.tedarik, icon: "✅" },
                                { label: "Verilemeyen", val: kpi.verilemeyen, icon: "⚠️" },
                                { label: "Spot", val: kpi.spot, icon: "🚚" },
                                { label: "Filo", val: kpi.filo, icon: "🏷️" },
                            ].map((k, i) => (
                                <Card key={i} className="h-28">
                                    <CardHeader className="flex items-center justify-between pb-2">
                                        <div className="text-sm font-medium text-gray-400">{k.icon} {k.label}</div>
                                        <Badge className="bg-white/10 text-gray-300 border-white/10">
                                            {lastUpdated ? `⏱ ${lastUpdated.toLocaleTimeString("tr-TR")}` : ""}
                                        </Badge>
                                    </CardHeader>
                                    <CardContent>
                                        <div className="text-2xl font-semibold tracking-tight">{Number(k.val).toLocaleString("tr-TR")}</div>
                                    </CardContent>
                                </Card>
                            ))}
                        </section>

                        {/* Proje tablosu — sticky başlık + kalan yüksekliği kaplayan scroll */}
                        <section>
                            <Card>
                                <CardHeader className="pb-3">
                                    <div className="flex items-center justify-between">
                                        <div>
                                            <CardTitle>Projeler (ODAK - Reel)</CardTitle>
                                            <CardDescription>
                                                {startDate} – {endDate}
                                                {lastUpdated ? `  •  Güncellendi: ${lastUpdated.toLocaleTimeString("tr-TR")}` : ""}
                                            </CardDescription>
                                        </div>
                                    </div>
                                </CardHeader>
                                <CardContent className="p-0">
                                    {odakRows.length === 0 ? (
                                        <div className="p-5 text-sm text-gray-400">Bu aralıkta kriterlere uyan veri bulunamadı.</div>
                                    ) : (
                                        <div className="overflow-auto max-h-[calc(100vh-260px)]">
                                            <table className="w-full text-sm">
                                                <thead className="sticky top-0 z-10 bg-gray-900/80 backdrop-blur">
                                                    <tr className="border-b border-white/10 text-left text-gray-400">
                                                        <th className="py-2 px-5">Proje</th>
                                                        <th className="px-3">Talep</th>
                                                        <th className="px-3">Tedarik</th>
                                                        <th className="px-3">Verilemeyen</th>
                                                        <th className="px-3">Spot</th>
                                                        <th className="px-3">Filo</th>
                                                        <th className="px-3">Uyum %</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {odakRows.map((r, i) => {
                                                        const uyum = r.Talep > 0 ? Math.round((r.Tedarik / r.Talep) * 100) : 0;
                                                        const color = uyum < 70 ? "#e74c3c" : uyum < 90 ? "#f39c12" : "#27ae60";
                                                        return (
                                                            <tr key={i} className="border-b border-white/5 transition-colors hover:bg-white/5">
                                                                <td className="py-2 px-5 font-medium text-gray-200">{r.ProjectName}</td>
                                                                <td className="px-3 text-gray-300">{r.Talep}</td>
                                                                <td className="px-3 text-gray-300">{r.Tedarik}</td>
                                                                <td className="px-3 text-gray-300">{r.Verilemeyen}</td>
                                                                <td className="px-3 text-gray-300">{r.Spot}</td>
                                                                <td className="px-3 text-gray-300">{r.Filo}</td>
                                                                <td className="px-3" style={{ color, fontWeight: "bold" }}>%{uyum}</td>
                                                            </tr>
                                                        );
                                                    })}
                                                </tbody>
                                                <tfoot>
                                                    <tr className="border-t border-white/10 bg-white/5/5">
                                                        <td className="py-2 px-5"><strong>TOPLAM</strong></td>
                                                        <td className="px-3">{odakRows.reduce((s, r) => s + (r.Talep || 0), 0).toLocaleString("tr-TR")}</td>
                                                        <td className="px-3">{odakRows.reduce((s, r) => s + (r.Tedarik || 0), 0).toLocaleString("tr-TR")}</td>
                                                        <td className="px-3">{odakRows.reduce((s, r) => s + (r.Verilemeyen || 0), 0).toLocaleString("tr-TR")}</td>
                                                        <td className="px-3">{odakRows.reduce((s, r) => s + (r.Spot || 0), 0).toLocaleString("tr-TR")}</td>
                                                        <td className="px-3">{odakRows.reduce((s, r) => s + (r.Filo || 0), 0).toLocaleString("tr-TR")}</td>
                                                        <td className="px-3" style={{
                                                            fontWeight: "bold",
                                                            color: (() => {
                                                                const tTalep = odakRows.reduce((s, r) => s + (r.Talep || 0), 0);
                                                                const tTed = odakRows.reduce((s, r) => s + (r.Tedarik || 0), 0);
                                                                const pct = tTalep > 0 ? Math.round((tTed / tTalep) * 100) : 0;
                                                                return pct < 70 ? "#e74c3c" : pct < 90 ? "#f39c12" : "#27ae60";
                                                            })()
                                                        }}>
                                                            {(() => {
                                                                const tTalep = odakRows.reduce((s, r) => s + (r.Talep || 0), 0);
                                                                const tTed = odakRows.reduce((s, r) => s + (r.Tedarik || 0), 0);
                                                                const pct = tTalep > 0 ? Math.round((tTed / tTalep) * 100) : 0;
                                                                return `%${pct}`;
                                                            })()}
                                                        </td>
                                                    </tr>
                                                </tfoot>
                                            </table>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>
                        </section>
                    </>
                )}
            </main>

            {/* Alt Bilgi */}
            <footer className="w-full px-6 pb-10 pt-2 text-xs text-gray-500">
                © {new Date().getFullYear()} CargoFlow • ODAK verisiyle canlı görünüm
            </footer>
        </div>
    );
};

export default AnaSayfa;
